    INITIALIZE_PLAYER_CONTROLS(state){
      // state.thirdpersonContainer for both camera and person
      state.scene.add(state.thirdpersonContainer);

      // Model and animation actions
      let model, skeleton, mixer, clock, numAnimations = 0,
          movingForward = false, mousedown = false;
      clock = new Clock();
      const allActions = [];
      const baseActions = {
        agree: { weight: 1 },
        headShake: { weight: 1 },
        walk: { weight: 0 },
        run: { weight: 0 }
      };

      function setWeight( action, weight ) {
        action.enabled = true;
        action.setEffectiveTimeScale( 1 );
        action.setEffectiveWeight( weight );
      }
      function activateAction( action ) {
        const clip = action.getClip();
        const settings = baseActions[ clip.name ];
        setWeight( action, settings.weight );
        action.play();
      }

      const loader = new GLTFLoader();
      if(!state.thirdpersonLoaded) loader.load( '../catface.glb', function ( gltf ) {
        model = gltf.scene;
        model.name = "Person";
        state.thirdpersonContainer.add(model);
        model.traverse( function ( object ) {
          if ( object.isMesh ) {
            object.castShadow = true;
          }   
        });
        
        skeleton = new SkeletonHelper( model );
        skeleton.visible = false;
        state.thirdpersonContainer.add( skeleton );
        const animations = gltf.animations;
        mixer = new AnimationMixer( model );

        let a = animations.length;
        for ( let i = 0; i < a; ++ i ) {
          let clip = animations[ i ];
          const name = clip.name;
          if ( baseActions[ name ] ) {
            const action = mixer.clipAction( clip );
            activateAction( action );
            baseActions[ name ].action = action;
            allActions.push( action );
            numAnimations += 1;
          }
        }
      });

      const animate = function () {
        if(state.thirdperson) requestAnimationFrame( animate );
        for ( let i = 0; i < numAnimations; i++ ) {
          const action = allActions[ i ];
          const clip = action.getClip();
          const settings = baseActions[clip.name];
          // settings.weight = action.getEffectiveWeight();
        }

        if(mixer) {
          const mixerUpdateDelta = clock.getDelta();
          mixer.update( mixerUpdateDelta );
        }
        
        if(movingForward) {
          // Get the X-Z plane in which camera is looking to move the player
          state.thirdpersoncamera.getWorldDirection(state.tempCameraVector);
          const cameraDirection = state.tempCameraVector.setY(0).normalize();
          
          // Get the X-Z plane in which player is looking to compare with camera
          model.getWorldDirection(state.tempModelVector);
          const playerDirection = state.tempModelVector.setY(0).normalize();

          // Get the angle to x-axis. z component is used to compare if the angle is clockwise or anticlockwise since angleTo returns a positive value
          const cameraAngle = cameraDirection.angleTo(state.xAxis) * (cameraDirection.z > 0 ? 1 : -1);
          const playerAngle = playerDirection.angleTo(state.xAxis) * (playerDirection.z > 0 ? 1 : -1);
          
          // Get the angle to rotate the player to face the camera. Clockwise positive
          const angleToRotate = playerAngle - cameraAngle;
          
          // Get the shortest angle from clockwise angle to ensure the player always rotates the shortest angle
          let sanitisedAngle = angleToRotate;
          if(angleToRotate > Math.PI) {
            sanitisedAngle = angleToRotate - 2 * Math.PI
          }
          if(angleToRotate < -Math.PI) {
            sanitisedAngle = angleToRotate + 2 * Math.PI
          }
          
          // Rotate the model by a tiny value towards the camera direction
          model.rotateY(
            Math.max(-0.10, Math.min(sanitisedAngle, 0.10))
          );
          state.thirdpersonContainer.position.add(cameraDirection.multiplyScalar(0.10));
          state.camera.lookAt(state.thirdpersonContainer.position.clone().add(state.thirdPersonCameraOrigin));
        }

        state.renderer.render( state.scene, state.thirdpersoncamera );
      };

      animate();

      if(!state.thirdpersonLoaded){
        // Key and mouse events
        window.addEventListener("keydown", (e) => {
          const { keyCode } = e;
          if(keyCode === 87 || keyCode === 38) {
            baseActions.agree.weight = 0;
            baseActions.run.weight = 5;   
            activateAction(baseActions.run.action);
            activateAction(baseActions.agree.action);
            movingForward = true;
          }
        });

        window.addEventListener("keyup", (e) => {
          const { keyCode } = e;
          if(keyCode === 87 || keyCode === 38) {
            baseActions.agree.weight = 1;
            baseActions.run.weight = 0;
            activateAction(baseActions.run.action);
            activateAction(baseActions.agree.action);
            movingForward = false;
          }
        });

        window.addEventListener("pointerdown", (e) => {
          mousedown = true;
        });

        window.addEventListener("pointerup", (e) => {
          mousedown = false;
        });

        window.addEventListener("pointermove", (e) => {
          if(mousedown) {
            const { movementX, movementY } = e;
            const offset = new Spherical().setFromVector3(
              state.thirdpersoncamera.position.clone().sub(state.thirdPersonCameraOrigin)
            );
            const phi = offset.phi - movementY * 0.02;
            offset.theta -= movementX * 0.02;
            offset.phi = Math.max(0.01, Math.min(0.60 * Math.PI, phi));
            state.thirdpersoncamera.position.copy(
              state.thirdPersonCameraOrigin.clone().add(new Vector3().setFromSpherical(offset))
            );
            state.thirdpersoncamera.lookAt(state.thirdpersonContainer.position.clone().add(state.thirdPersonCameraOrigin));
          }
        });
        state.thirdpersonLoaded = true;
      }
    },
