    },
    createBuildingObb: function(lat, long, lat2, long2, xAnchorDisp, yAnchorDisp, oBB){
      // obb = oBB = NEO("m_matrix")
      // Scalefactor is used in all xyz directions
      console.log("oBB: "+oBB);
      let u = UnitsUtils.datumsToSpherical(lat, long);
      let u2 = UnitsUtils.datumsToSpherical(lat2, long2);

      var v2Length = Math.sqrt((oBB.v2.x*oBB.v2.x)+(oBB.v2.y*oBB.v2.y)+(oBB.v2.z*oBB.v2.z));
      var v3Length = Math.sqrt((oBB.v3.x*oBB.v3.x)+(oBB.v3.y*oBB.v3.y));

      // Setting the dimentions of the bounding box
      var geoW, geoH, geoL;
      geoW = v2Length*this.scaleFactor;
      geoH = oBB.v3.z*this.scaleFactor;
      geoL = v3Length*this.scaleFactor;
      store.state.bv.coords = { x:geoW/2, y:geoH/2, z:-geoL/2 };
      //var geometry = new BoxGeometry( geoW, geoH, geoL );
      var geometry = this.lineDashBox( geoW, geoH, geoL );
      // Moving anchor from center of the bounding box
      const xAnchorDisplacement = ((oBB.v2.x/2)-xAnchorDisp); // Used to set box rotation point at left side of building
      const yAnchorDisplacement = -((oBB.v3.y/2)-yAnchorDisp);
      geometry.translate( xAnchorDisplacement*this.scaleFactor, (geoH/2.0), yAnchorDisplacement*this.scaleFactor ); // Set anchor location of box

      // Set the initial position of the bounding box. Based on gps anchor u.
      //const material = new MeshPhongMaterial({color: 0x6666FF, side: DoubleSide, emissive: 0x666666, transparent:true, opacity:1});
      //var mesh = new Mesh( geometry, material );
      var mesh = new LineSegments( geometry, new LineDashedMaterial( { color: 0xffaa00, dashSize: 3, gapSize: 1 } ) );
      mesh.computeLineDistances();
      mesh.position.x = 0;
      mesh.position.y = oBB.v1.z;
      mesh.position.z = 0;

      // Calculating rotation based on the two gps points
      // The u and u2 is the base new coordinate system. Obb vector will create the angle.
      const xOffsetToDrawing = (u2.x-u.x)-(oBB.v1.x*this.scaleFactor); // Difference between world vector value and map vector value
      const yOffsetToDrawing = (u2.y-u.y)-(oBB.v1.y*this.scaleFactor); // Difference between world vector value and map vector value
      mesh.rotation.setFromVector3(new Vector3( 0, (Math.PI/2)-(Math.atan2(xOffsetToDrawing, yOffsetToDrawing)), 0)); // Rotate building using anchor

      mesh.updateMatrix();
      mesh.matrixAutoUpdate = false;
      mesh.castShadow = false;
      mesh.renderOrder=1;
      return(mesh);
    },
    drawRoomFromPolyline(buildingbox, vx, vy, vz, height, polyline, lat, roomuri, color, opacity){
      var polyArray = [];
      if(polyline != ""){
        polyline = polyline.replace("^^neo:a_matrix-3xm", "");
        polyline = polyline.replace("[", "");
        polyline = polyline.replace("]", "");
        polyArray = polyline.split(",");
      }
      vx = vx*this.scaleFactor;
      vy = vy*this.scaleFactor;
      vz = vz*this.scaleFactor;
      const material = new MeshPhongMaterial({color: color, side: DoubleSide, emissive: 0x666666, transparent:true, opacity:opacity});
      const wireMaterial = new MeshBasicMaterial({
        color: 'white',
        polygonOffset: true,
        polygonOffsetFactor: 1,
        polygonOffsetUnit: 1
      });
      const polyShape = new Shape();
      const points = [];
      var v1 = new Vector3( 0, vz, 0 );
      var v2 = new Vector3( 0, vz+(height*this.scaleFactor), 0 );
      var path = new LineCurve3( v1, v2 )
      var i = 0;
      while (polyArray.length > 1) {
        const polyXYZ = polyArray.splice(0, 3); // Puts 3 first object from array in polyXYZ, and removes from polyArray
        const x = (polyXYZ[0]*this.scaleFactor);
        const y = (polyXYZ[1]*this.scaleFactor);
        if(i == 0){
          polyShape.moveTo( (-x+vy), (-y-vx), vz );
          i = i+1;
        } else {
          polyShape.lineTo( (-x+vy), (-y-vx), vz );
        }
      }
      polyShape.autoClose = true;
      const extrudeSettings = { 
        extrudePath: path,
      };
      const polyGeometry = new ExtrudeGeometry( polyShape, extrudeSettings );
      const polyMesh = new Mesh( polyGeometry, material ) ;

      // Test to add border on box
      const wireMesh = new Mesh( polyGeometry, wireMaterial );
      polyMesh.add(wireMesh);

      //console.log(roomuri);
      polyMesh.name = roomuri;
      store.state.bv.boundingBoxDrawed.push(String(polyline));
      buildingbox.add(polyMesh);
      return(buildingbox);
    },
    raycast( event ) {
      if(!store.state.bv.lockSelection){
        let canvasBounds = this.$el.getBoundingClientRect();
        store.state.bv.mouseVector.x = ((event.clientX - canvasBounds.left) / (canvasBounds.right - canvasBounds.left)) * 2 - 1;
        store.state.bv.mouseVector.y  = -((event.clientY - canvasBounds.top) / (canvasBounds.bottom - canvasBounds.top)) * 2 + 1;
        //console.log(store.state.bv.mouseVector.x+":"+store.state.bv.mouseVector.y);
        return this.CALL_RAYCAST();
      }
    },
    async setLabel( event ) {
