      let buildingbox = store.state.bv.scene.getObjectByName("buildingbox");
      let canvasBounds = this.$el.getBoundingClientRect();
      store.state.bv.mouseVector.x = ((event.clientX - canvasBounds.left) / (canvasBounds.right - canvasBounds.left)) * 2 - 1;
