    addLabelToDatabase(title, description, position, tags, responsible, imageuri, state, labelID){
        let matrixString = "[0,0,0,0,0,0,"+position.x+","+position.y+","+position.z+"]^^neo:a_matrix-3m";
        const labelBlank = u.getBlankNode("Label: "+title)
