        if(!store.state.blankExisted){
          store.state.rs.tempRdfStore = $rdf.graph();
          tags.forEach(tag => {
            store.state.rs.tempRdfStore.add(labelBlank, ns.TAG("tag"), tag, $rdf.default);
          });
