          store.state.rs.tempRdfStore.add(labelBlank, ns.RDFS("label"), $rdf.literal(title, 'en'), $rdf.default);
          store.state.rs.tempRdfStore.add(labelBlank, ns.RDFS("comment"), description, $rdf.default);
          store.state.rs.tempRdfStore.add(labelBlank, ns.TAG("tag"), "I4TASK"+"."+labelID, $rdf.default);
          store.state.rs.tempRdfStore.add(labelBlank, ns.IFOUR("taskStatus"), state, $rdf.default);
          store.state.rs.tempRdfStore.add(labelBlank, ns.FOAF("aimChatID"), $rdf.sym(responsible), $rdf.default); // Who the issue is assigned to.
          store.state.rs.tempRdfStore.add(labelBlank, ns.FOAF("maker"), $rdf.sym(store.state.webId), $rdf.default); // Concept verified and used by Fred - foaf:Maker
          store.state.rs.tempRdfStore.add(labelBlank, ns.FOAF("image"), $rdf.sym(imageuri), $rdf.default);
          store.state.rs.tempRdfStore.add(labelBlank, ns.NEO("m_matrix"), matrixString, $rdf.default);
          let turtle = u.storeToTurtle(store.state.rs.tempRdfStore, "");
          turtle = ur.modifyTurtle(turtle);
          console.log(turtle);
          ur.uploadTriples(this.$route.query.location+"i", turtle, false).then((successfulFetch) => {
            console.log(successfulFetch);
          });
        }
    },
    removeLabelFromDatabase(){

    },
    showLabelFromDatabase(tag){
      store.state.rs.rdfStore.match(null, ns.TAG("tag"), null).forEach(item => {
        if(item.object.value.includes("I4TASK")){
