                responsible = foundItem.object.value;
                responsibleName = store.state.rs.rdfStore.match($rdf.sym(foundItem.object.value), ns.FOAF("name"), null)[0].object.value || "";
            });
            let matrix = "";
            let position = new Vector3( 0, 0, 0);
            store.state.rs.rdfStore.match(item.subject, ns.NEO("t_"), null).forEach(foundMatrix => {
                matrix = foundMatrix.object.value;
            });
            console.log("Matrix: "+matrix);
            if(matrix.length>=10){
                matrix = matrix.replace(']^^neo:a_matrix-3m', '');
                matrix = matrix.replace('[0,0,0,0,0,0,', '');
                const matrixArray = matrix.split(",");
                position.x = parseInt(matrixArray[0]);
                position.y = parseInt(matrixArray[1]);
                position.z = parseInt(matrixArray[2]);
            }
