    async setupBuildingBox() {
      const axesHelper = new AxesHelper();
      store.state.bv.scene.add( axesHelper );
      const IFCmetadata = await ifcu.getIFCmetaDataFromJson(this.$route.query.location+"home/IFC/building.json"); // Create function for storing in local storage
      const buildingLat = IFCmetadata.buildinglat;
      const buildingLong = IFCmetadata.buildinglong;
      const buildingLat2 = IFCmetadata.building2lat;
      const buildingLong2 = IFCmetadata.building2long;
      const xAnchorDisplacement = IFCmetadata.xAnchorDisplacement; // Used to set box rotation point at left side of building
      const yAnchorDisplacement = IFCmetadata.yAnchorDisplacement; // 10.33 Used to set box rotation point at right y level
      const color1 = 0xFF4433;
      let oBB = IFCmetadata.buildingdimensions; // First vector goes from buildingpoint2 to buildingpoint1 in meters
      this.buildingLat = buildingLat;
      this.scaleFactor = 1/(Math.cos(buildingLat*Math.PI/180)); // Translates meters into epsg-3857

      const buildingbox = this.createBuildingObb(buildingLat, buildingLong, buildingLat2, buildingLong2, xAnchorDisplacement, yAnchorDisplacement, oBB, color1);
      buildingbox.name = "buildingbox";
      
      const u = UnitsUtils.datumsToSpherical(buildingLat, buildingLong);
      store.state.bv.buildingboxPosition = {x: u.x, y: 0, z:u.y };
      // Move the map so the zero point of the scene is same as zero point of buildingbox
      store.state.bv.scene.getObjectByName("map").position.set(-store.state.bv.buildingboxPosition.x, 0, store.state.bv.buildingboxPosition.z);
      this.ADD_TO_SCENE({ buildingbox: buildingbox });
      store.state.bv.focusobject = store.state.bv.scene.getObjectByName("buildingbox");
      this.zoomToObject();
      this.RENDER();
    },
