    moveToObject() {
      var target = new Vector3();
      var size = new Vector3();
      var center = new Vector3();
      var boundingBox = new Box3().setFromObject( store.state.bv.INTERSECTED );
      store.state.bv.animate = true;
      size = boundingBox.getSize(size);
      center = boundingBox.getCenter( center );
      console.log("SizeX:"+size.x+" SizeY:"+size.y);
      if(size.x >= size.y){ // Find longest side of box
        store.state.bv.camerafocuswidth = size.x;
      } else {
        store.state.bv.camerafocuswidth = size.y;
      }
      let start, previousTimestamp;
      var animateDown = false;
      //this.CONVERT_TO_SPHERICAL({ lat: store.state.bv.focuslat, long: store.state.bv.focuslong }).then(u => {
      store.state.bv.INTERSECTED.getWorldPosition( target );
      var newCameraPosX = center.x + (15+store.state.bv.camerafocuswidth*0.5);
      var newCameraPosZ = center.y + (15+store.state.bv.camerafocuswidth*0.5);
      var newCameraPosY = center.z + (15+store.state.bv.camerafocuswidth*0.5);

      var newTargetPosX = center.x;
      var newTargetPosY = center.y;
      var newTargetPosZ = center.z;

      var oldCameraPosX = store.state.bv.camera.position.x;
      var oldCameraPosY = store.state.bv.camera.position.z;
      var oldCameraPosZ = store.state.bv.camera.position.y;

      var oldTargetPosX = store.state.bv.controls.target.x;
      var oldTargetPosY = store.state.bv.controls.target.y;
      var oldTargetPosZ = store.state.bv.controls.target.z;

      var counter = 2;

      var currentCameraPosX = oldCameraPosX;
      var currentCameraPosY = oldCameraPosY;
      var currentCameraPosZ = oldCameraPosZ;
      var currentTargetPosX = oldTargetPosX;
      var currentTargetPosY = oldTargetPosY;
      var currentTargetPosZ = oldTargetPosZ;

      function step(timestamp){
        if(start === undefined){
          start = timestamp;
        }
        const elapsed = timestamp-start;
        if(previousTimestamp !== timestamp){
          currentCameraPosX = (currentCameraPosX-((oldCameraPosX-newCameraPosX)/15));
          currentCameraPosY = (currentCameraPosY-((oldCameraPosY-newCameraPosY)/15));
          currentCameraPosZ = (currentCameraPosZ-((oldCameraPosZ-newCameraPosZ)/15));
          currentTargetPosX = (currentTargetPosX-((oldTargetPosX-newTargetPosX)/15));
          currentTargetPosY = (currentTargetPosY-((oldTargetPosY-newTargetPosY)/15));
          currentTargetPosZ = (currentTargetPosZ-((oldTargetPosZ-newTargetPosZ)/15));
          store.state.bv.camera.position.set(currentCameraPosX, currentCameraPosZ, currentCameraPosY);
          store.state.bv.controls.target.set(currentTargetPosX, currentTargetPosY, currentTargetPosZ);
        }
        if(counter <= 15){
          previousTimestamp = timestamp;
          counter = counter+1;
          window.requestAnimationFrame(step);
        } else {
          if(!store.state.bv.autorotate){
            store.state.bv.animate = false;
          }
        }
      }
      window.requestAnimationFrame(step);
      //});
      console.log("Zoom to object");
    },
    showImplicitGeometry(shapes, scaleF, heightSc, bboxMesh, geoL, geoH){
      const startTime = performance.now();
      const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");

      let shader = /* glsl */ `

      float opUnion( float d1, float d2 ) { return min(d1,d2); }

      float opSubtraction( float d1, float d2 ) { return max(-d1,d2); }

      float opIntersection( float d1, float d2 ) { return max(d1,d2); }

      float dot2( in vec2 v ) { return dot(v,v); }
      float ndot( in vec2 a, in vec2 b ) { return a.x*b.x - a.y*b.y; }

      float opSmoothUnion( float d1, float d2, float k ) {
        float h = clamp( 0.5 + 0.5*(d2-d1)/k, 0.0, 1.0 );
        return mix( d2, d1, h ) - k*h*(1.0-h); }

      float opSmoothSubtraction( float d1, float d2, float k ) {
          float h = clamp( 0.5 - 0.5*(d2+d1)/k, 0.0, 1.0 );
          return mix( d2, -d1, h ) + k*h*(1.0-h); }

      float opSmoothIntersection( float d1, float d2, float k )
      {
          float h = clamp( 0.5 - 0.5*(d2-d1)/k, 0.0, 1.0 );
          return mix( d2, d1, h ) + k*h*(1.0-h); }

      float sdTriangle( in vec2 p, in vec2 p0, in vec2 p1, in vec2 p2 )
      {
          vec2 e0 = p1-p0, e1 = p2-p1, e2 = p0-p2;
          vec2 v0 = p -p0, v1 = p -p1, v2 = p -p2;
          vec2 pq0 = v0 - e0*clamp( dot(v0,e0)/dot(e0,e0), 0.0, 1.0 );
          vec2 pq1 = v1 - e1*clamp( dot(v1,e1)/dot(e1,e1), 0.0, 1.0 );
          vec2 pq2 = v2 - e2*clamp( dot(v2,e2)/dot(e2,e2), 0.0, 1.0 );
          float s = sign( e0.x*e2.y - e0.y*e2.x );
          vec2 d = min(min(vec2(dot(pq0,pq0), s*(v0.x*e0.y-v0.y*e0.x)),
                           vec2(dot(pq1,pq1), s*(v1.x*e1.y-v1.y*e1.x))),
                           vec2(dot(pq2,pq2), s*(v2.x*e2.y-v2.y*e2.x)));
          return -sqrt(d.x)*sign(d.y);
      }

      float opExtrussion( in vec3 p, in float sdf, in float h )
      {
          vec2 w = vec2( sdf, abs(p.z) - h );
        	return min(max(w.x,w.y),0.0) + length(max(w,0.0));
      }

      float sdCross( in vec2 p, in vec2 b, float r )
      {
          p = abs(p); p = (p.y>p.x) ? p.yx : p.xy;
          vec2  q = p - b;
          float k = max(q.y,q.x);
          vec2  w = (k>0.0) ? q : vec2(b.y-p.x,-k);
          return sign(k)*length(max(w,0.0)) + r;
      }

      float sdBox( vec3 p, vec3 b )
      {
        vec3 q = abs(p) - b;
        return length(max(q,0.0)) + min(max(q.x,max(q.y,q.z)),0.0);
      }

      float sdSphere( vec3 p, float s )
      {
        return length(p)-s;
      }

      float extRoom(vec3 p){
        vec2 shapes[`+shapes.length+`];
        `
        for(var i=0; i<shapes.length; ++i) {
            shader = shader+`shapes[`+i+`] = `+shapes[i]+`;
            `;
        }
        shader = shader+`
        float t1 = sdTriangle( p.xy, shapes[0], shapes[1], shapes[2] );
        float t2 = sdTriangle( p.xy, shapes[3], shapes[4], shapes[5] );
        float t3 = sdTriangle( p.xy, shapes[6], shapes[7], shapes[8] );
        float t4 = sdTriangle( p.xy, shapes[9], shapes[10], shapes[11] );
        float t5 = sdTriangle( p.xy, shapes[12], shapes[13], shapes[14] );
        float t6 = sdTriangle( p.xy, shapes[15], shapes[16], shapes[17] );
        float t7 = sdTriangle( p.xy, shapes[18], shapes[19], shapes[20] );
        float t8 = sdTriangle( p.xy, shapes[21], shapes[22], shapes[23] );

        float t2d = opUnion(opUnion(opUnion(opUnion(opUnion(opUnion(opUnion( t1, t2 ), t3), t4), t5), t6), t7), t8);
        float t3d = opExtrussion(p, t2d, `+heightSc/2+`);
        return t3d;
      }

      float surface (vec3 p) {
        p = vec3(p.z, p.x, p.y );
        return extRoom(p)+`+this.bval+`;
      }
      `

      const mesh = implicitMesh(256, shader)
      /*const javaMesh = require('implicit-mesh');
      const mesh = javaMesh(64, function (x,y,z) {
