        //return Math.min(ig.methods.impBox(x,y,z,0.8,0.6,0.1), ig.methods.impBox(x,y,z,0.2,0.6,0.8));
        return ig.methods.opExtrussion(p, ig.methods.sdTriangle(p, p0, p1, p2), heightSc/2);
