              factor = 4;
              if(buildingbox.children[i]){
                const currentMesh = buildingbox.children[i];
                const newPosition = {x:0, y:heightAboveGround*factor, z:0};
                const currentPosition = {x:currentMesh.position.x, y:currentMesh.position.y, z:currentMesh.position.z};
                const tween = new store.state.bv.TWEEN.Tween(currentPosition) // Create a new tween that modifies 'coords'.
