async function comunicaQuery(sparqlStr,rowFunction,quadStore,callback) {
  var startTime = performance.now();
  const myEngine = Comunica.newEngine();
  const config = { sources: [quadStore] };
  const result = await myEngine.query(sparqlStr, config);
  result.bindingsStream.on('data',(binding)=> {
    for(let field of binding._root.entries){
      let newRow = [];
      // comunica has [ key, value ], rdflib wants { key : vaue }
      for(let field of binding._root.entries){
        newRow[field[0]]=field[1];
      }
      rowFunction(newRow);
    }
  });
  /*result.bindingsStream.on('data', (binding) => {
    console.log(binding.get('?floor').value);
  });*/
  result.bindingsStream.on('end', () => {
    var endTime = performance.now();
    console.log(`Communicaquery used: ${endTime - startTime} milliseconds`);
    callback();
  });
}

async function rdflibQuery(queryString){
  return new Promise(async (resolve,reject)=>{
    try {
      let quadStore = new N3.Store();
      store.state.rs.rdfStore.match(null, null, null).forEach(stm => {
        quadStore.addQuad( stm.subject,stm.predicate,stm.object )
      });
      //let quadStore = store.state.rs.rdfStore;
      let allResults = []
      comunicaQuery(queryString, (results)=>{
        allResults.push(results)
      },quadStore,()=>{resolve(allResults)})
    }
    catch(e) { console.log(e); reject(e) }
 });
}

async function test(queryString){
  var startTime = performance.now();
  const results = await rdflibQuery(queryString);
  var endTime = performance.now();
  console.log(`Whole process took: ${endTime - startTime} milliseconds`);
