const bmu = {};

const $rdf = require('rdflib');
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader.js';
import store from '../store';
import ur from './FetchOperations.js';
import so from './util-s.js';
import a from './util-a.js';
import ns from './Prefixes.js';

bmu.getEmployeeList = async function(uri){
  return new Promise(async (resolve,reject)=>{
    ur.fetchAndSaveTurtle(uri, true).then((response) => {
      console.log("Get employees from: "+uri);
      let employeeList = [];
      let employeeURIs = [];

      // Get all URIs
      let tripleArray = store.state.rs.rdfStore.match($rdf.sym(uri), ns.ORG("hasMember"), null);
      tripleArray.forEach(item => {
          if(!employeeURIs.includes(item.object.value)) { // Check if it contains the exact same or without /i in the end.
            console.log("Found employee..");
            employeeURIs.push(item.object.value);
          }
      });

      employeeURIs.forEach((emplItem, i) => {
        employeeList.push({ filename: 'pod', personuri: emplItem, initials: "", name: emplItem, color: so.makeRandomColor() });
      });

      // Get person names
      employeeList.forEach((listitem, iNum) => {
        ur.fetchAndSaveTurtle(listitem.personuri, true).then((response) => {
          try{
            let personName = store.state.rs.rdfStore.match($rdf.sym(listitem.personuri), ns.FOAF("name"), null)[0].object.value || "";
            listitem.name = personName;
            console.log("Name: "+personName);
            listitem.initials = so.getInitials(personName);
          } catch (error){
            console.log(error);
          }
          
          if(iNum === employeeList.length-1){
            console.log("Returning list");
            resolve(employeeList);
            //return employeeList;
          }
        });
      });
    });
  });
}

