bmu.getMeshHeightAboveGround = function(mesh){
  let heightAboveGround = 1000;
  console.log(mesh);
  try{
    if(mesh.geometry){
      for(let y = 1; y<=mesh.geometry.attributes.position.array.length; y=y+3){
        heightAboveGround = Math.min(mesh.geometry.attributes.position.array[y], heightAboveGround);
      }
    }
    if(mesh.children[0].geometry){
      for(let y = 1; y<=mesh.children[0].geometry.attributes.position.array.length; y=y+3){
        heightAboveGround = Math.min(mesh.children[0].geometry.attributes.position.array[y], heightAboveGround);
      }
    }
    if(mesh.children[0].children[0].geometry){
      for(let y = 1; y<=mesh.children[0].children[0].geometry.attributes.position.array.length; y=y+3){
        heightAboveGround = Math.min(mesh.children[0].children[0].geometry.attributes.position.array[y], heightAboveGround);
      }
    }
  } catch(error){
    console.log(error);
  }
  return heightAboveGround;
}

bmu.downloadGLTFfromTrinpod = async function(GLTFurl, mTag){
  try {
    const res = await window.solid.session.fetch(
      GLTFurl, {
        method: "GET",
        credentials: "include",
        });
        console.log(res);
      let filedata = await res.arrayBuffer();
      let fileurl = URL.createObjectURL(new Blob([filedata], { type: "application/gltf"}));
      console.log("Flag: "+store.state.bv.GLTFloadingFlag);
      if(!store.state.bv.GLTFloadingFlag){ // Check if something already loading
        bmu.loadGLTF(fileurl, mTag);
        store.state.bv.GLTFloadingQueue.push(fileurl);
      } else {
        console.log("Something is already loading, need queue. Putting in queue");
        store.state.bv.GLTFloadingQueue.push(fileurl);
      }
  } catch (error) {
    console.log(error);
  }
}

bmu.loadGLTF = async function(fileurl, mTag){
  const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");
  const loader = new GLTFLoader();
  console.log("Starting to load "+mTag+" gltf..")
  store.state.bv.GLTFloadingFlag = true;
  loader.load(
    fileurl, //"./gltf/NMH.Y.SYKEHUS.HN.H.MOIRANA.SJOFORSGATA.HOVEDBYGG.gltf",
    function ( gltf ) {
      const model = gltf.scene;
      model.scale.set(store.state.bv.scaleFactor, store.state.bv.scaleFactor, store.state.bv.scaleFactor);
      model.name = mTag;
      buildingbox.add( model );
    },
    function ( progress ) {
      let progressPercent = ( progress.loaded / progress.total * 100 );
      console.log(progressPercent+'% loaded' );
      if(progressPercent==100){ 
        console.log("GLTF loading finished!");
        setTimeout(function() { window.requestAnimationFrame(() => {store.state.bv.renderer.render(store.state.bv.scene, store.state.bv.camera);}); }, 300);
        store.state.bv.GLTFloadingFlag = false;
        // Check the loading queue
        store.state.bv.GLTFloadingQueue = a.removeFirstElement(store.state.bv.GLTFloadingQueue);
        console.log(store.state.bv.GLTFloadingQueue.length);
        if(store.state.bv.GLTFloadingQueue.length>=1){
          console.log("Something found in queue");
          bmu.loadGLTF(store.state.bv.GLTFloadingQueue[0], mTag);
        }
      }
    },
    function ( error ) {
      console.log( 'An error happened: '+error );
      store.state.bv.GLTFloadingFlag = false;
      // Check the loading queue
      store.state.bv.GLTFloadingQueue = a.removeFirstElement(store.state.bv.GLTFloadingQueue);
      if(store.state.bv.GLTFloadingQueue.length>=1){
        bmu.loadGLTF(store.state.bv.GLTFloadingQueue[0], mTag);
      }
    }
  );
}

bmu.loadGeometryUsingTag = function(mTag, currentURL, ifcTypes){
  ifcTypes.forEach(ifctype => {
    let currentTag = mTag+"."+ifctype;
    if(!store.state.bv.gltfLoadedList.includes(currentTag) || ifcTypes == "HOVEDBYGG"){
      const GLTFurl = currentURL+"home/GLTF/"+currentTag+".gltf";
      bmu.downloadGLTFfromTrinpod(GLTFurl, currentTag);
      store.state.bv.gltfLoadedList.push(currentTag);
    }
  });
}

bmu.unloadGeometryUsingTag = function(mTag, ifcTypes){
  const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");
  ifcTypes.forEach(ifctype => {
    let currentTag = mTag+"."+ifctype;
    if(store.state.bv.gltfLoadedList.includes(currentTag)){
      try{
        let meshToRemove = store.state.bv.scene.getObjectByName(currentTag);
        buildingbox.remove(meshToRemove);
        store.state.bv.gltfLoadedList = a.removeValueFromArray(store.state.bv.gltfLoadedList, currentTag);
        //store.state.bv.renderer.render(store.state.bv.scene, store.state.bv.camera);
      } catch(error){
        console.log(error);
      }
    }
  });
}

export default bmu;
